    },
    {
      key: '/canvas-template',
      label: '画布模板',
    },
  ];

  return (
    <Layout style={{ minHeight: '100vh' }}>
      <Header
        style={{
          display: 'flex',
          alignItems: 'center',
          background: colorBgContainer,
          padding: '0 24px',
        }}
      >
        <h2 style={{ margin: 0, marginLeft: collapsed ? 16 : 24 }}>
          画布管理系统
