import {
  Table,
  Tag,
  Space,
  Button,
  Input,
  Select,
  Typography,
  Collapse,
  message,
  Modal,
} from 'antd';
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import type { ColumnsType } from 'antd/es/table';
import { mockCanvasList, statusMap, Canvas } from '../mock/canvasList';
import {
  SearchOutlined,
  PlusOutlined,
  EyeOutlined,
  EditOutlined,
  PauseCircleOutlined,
  PlayCircleOutlined,
  DeleteOutlined,
  LinkOutlined,
  UnlinkOutlined,
} from '@ant-design/icons';

const { Title } = Typography;
const { Panel } = Collapse;

export default function CanvasList() {
  const navigate = useNavigate();
  const [searchText, setSearchText] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [data, setData] = useState<Canvas[]>(mockCanvasList);
  const [expandedRowKeys, setExpandedRowKeys] = useState<React.Key[]>([]);

  // 处理二次触达按钮点击
  const handleSecondReach = (canvasId: number) => {
    navigate(`/second-reach-config/${canvasId}`);
  };

  // 处理查看画布
  const handleView = (record: Canvas) => {
    message.info(`查看画布：${record.name}`);
  };

  // 处理编辑画布
  const handleEdit = (record: Canvas) => {
    message.info(`编辑画布：${record.name}`);
  };

  // 处理启停画布
  const handleToggleStatus = (record: Canvas) => {
    const newStatus = record.status === 'active' ? 'paused' : 'active';
    const newData = data.map((item) =>
      item.id === record.id ? { ...item, status: newStatus } : item
    );
    setData(newData);
    message.success(
      `画布已${newStatus === 'active' ? '启用' : '暂停'}`
    );
  };

  // 处理删除画布
  const handleDelete = (record: Canvas) => {
    Modal.confirm({
      title: '确认删除',
      content: `确定要删除画布"${record.name}"吗？此操作不可恢复。`,
      onOk: () => {
        const newData = data.filter((item) => item.id !== record.id);
        setData(newData);
        message.success('画布已删除');
      },
    });
  };

  // 切换展开/折叠
  const toggleExpand = (canvasId: number) => {
    setExpandedRowKeys((prev) => {
      if (prev.includes(canvasId)) {
        return prev.filter((key) => key !== canvasId);
      }
      return [...prev, canvasId];
    });
  };

  const columns: ColumnsType<Canvas> = [
    {
      title: '画布名称',
      dataIndex: 'name',
      key: 'name',
      width: 200,
      render: (text: string, record: Canvas) => (
        <Space direction="vertical" size={0}>
          <span style={{ fontWeight: 500 }}>{text}</span>
          {record.secondReachCanvasName && (
            <span style={{ fontSize: 12, color: '#999' }}>
              <LinkOutlined style={{ marginRight: 4 }} />
              关联：{record.secondReachCanvasName}
            </span>
          )}
        </Space>
      ),
    },
    {
      title: '描述',
      dataIndex: 'description',
