  const handleEdit = (record: Canvas) => {
    message.info(`编辑画布：${record.name}`);
  };

  // 处理启停画布
  const handleToggleStatus = (record: Canvas) => {
    const newStatus = record.status === 'active' ? 'paused' : 'active';
    const newData = data.map((item) =>
      item.id === record.id ? { ...item, status: newStatus } : item
    );
    setData(newData);
    message.success(
      `画布已${newStatus === 'active' ? '启用' : '暂停'}`
    );
  };

  // 处理删除画布
  const handleDelete = (record: Canvas) => {
    Modal.confirm({
      title: '确认删除',
      content: `确定要删除画布"${record.name}"吗？此操作不可恢复。`,
      onOk: () => {
