input.content:
import {
  Steps,
  Form,
  Input,
  Select,
  Card,
  Button,
  Space,
  message,
  Divider,
  Radio,
} from 'antd';
import { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { ArrowLeftOutlined } from '@ant-design/icons';
import { mockCanvasList } from '../../mock/canvasList';

const { TextArea } = Input;
const { Option } = Select;

export default function SecondReachConfig() {
  const navigate = useNavigate();
  const { canvasId } = useParams<{ canvasId: string }>();
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState({
    audienceType: undefined as string | undefined,
    audienceName: '',
    relatedCanvasId: canvasId ? parseInt(canvasId, 10) : undefined,
    description: '',
  });
  const [form] = Form.useForm();

  // 获取当前画布信息
  const currentCanvas = canvasId
    ? mockCanvasList.find((c) => c.id === parseInt(canvasId, 10))
    : undefined;

  // 人群类型选项
  const audienceOptions = [
    { value: 'verified', label: '领券已核销' },
    { value: 'unverified', label: '领券未核销' },
  ];

  // 画布选项（排除当前画布）
  const canvasOptions = mockCanvasList
    .filter((c) => c.id !== parseInt(canvasId || '0', 10))
    .map((c) => ({
      value: c.id,
      label: c.name,
    }));

  // 处理表单值变化
  const handleValuesChange = (changedValues: Partial<typeof formData>) => {
    setFormData((prev) => ({ ...prev, ...changedValues }));
  };

  // 下一步
  const handleNext = async () => {
    try {
      if (currentStep === 0) {
        await form.validateFields(['audienceType', 'audienceName']);
      } else if (currentStep === 1) {
        await form.validateFields(['relatedCanvasId']);
      }
      setCurrentStep(currentStep + 1);
    } catch (error) {
      console.error('表单验证失败:', error);
    }
  };

  // 上一步
  const handlePrev = () => {
    setCurrentStep(currentStep - 1);
  };

  // 提交配置
  const handleSubmit = () => {
    form.validateFields().then(() => {
      // 模拟提交
      console.log('提交配置:', formData);
      message.success('二次触达配置已保存');
      navigate('/canvas-list');
    }).catch((error) => {
      console.error('表单验证失败:', error);
    });
  };

  // 取消
  const handleCancel = () => {
    navigate('/canvas-list');
  };

  const steps = [
    {
      title: '选择人群',
      description: '选择需要二次触达的人群类型',
    },
    {
      title: '关联画布',
      description: '选择关联的画布',
    },
    {
      title: '画布配置',
      description: '配置画布内容和触达策略',
    },
  ];

  return (
    <div>
      <Space style={{ marginBottom: 16 }}>
        <Button
          icon={<ArrowLeftOutlined />}
          onClick={() => navigate('/canvas-list')}
        >
          返回画布列表
        </Button>
      </Space>

      <Card>
        <Space direction="vertical" style={{ width: '100%' }} size="large">
          <div>
            <Steps current={currentStep} items={steps} style={{ marginBottom: 24 }} />
          </div>

          <Form
            form={form}
            layout="vertical"
            onValuesChange={handleValuesChange}
            initialValues={{
              audienceType: formData.audienceType,
              audienceName: formData.audienceName,
              relatedCanvasId: formData.relatedCanvasId,
              description: formData.description,
            }}
          >
            {/* 步骤 1：选择人群 */}
            {currentStep === 0 && (
              <Card
                title="第一步：选择需要二次触达的人群"
                size="small"
                style={{ maxWidth: 600 }}
              >
                <Form.Item
                  label="人群类型"
                  name="audienceType"
                  rules={[{ required: true, message: '请选择人群类型' }]}
                >
                  <Radio.Group optionType="button" buttonStyle="solid">
                    <Radio value="verified">领券已核销</Radio>
                    <Radio value="unverified">领券未核销</Radio>
                  </Radio.Group>
                </Form.Item>

                <Form.Item
                  label="人群名称"
                  name="audienceName"
                  rules={[{ required: true, message: '请填写人群名称' }]}
                  extra="请为该人群配置一个易于识别的名称"
                >
                  <Input placeholder="例如：618 活动领券已核销用户" />
                </Form.Item>

                <Divider />

                <div style={{ background: '#f5f5f5', padding: 16, borderRadius: 8 }}>
                  <div style={{ fontSize: 14, color: '#666', marginBottom: 8 }}>
                    <strong>当前画布信息：</strong>
                  </div>
                  {currentCanvas ? (
                    <Space direction="vertical" size="small">
                      <div>画布名称：{currentCanvas.name}</div>
                      <div>描述：{currentCanvas.description}</div>
                      <div>
                        状态：
                        <span style={{ color: '#1677ff' }}>
                          {
                            {
                              draft: '草稿',
                              active: '进行中',
                              paused: '已暂停',
                              ended: '已结束',
                            }[currentCanvas.status]
                          }
                        </span>
                      </div>
                    </Space>
                  ) : (
                    <div>未找到画布信息</div>
                  )}
                </div>
              </Card>
            )}

            {/* 步骤 2：关联画布 */}
            {currentStep === 1 && (
              <Card
                title="第二步：选择关联画布"
                size="small"
                style={{ maxWidth: 600 }}
              >
                <Form.Item
                  label="关联画布"
                  name="relatedCanvasId"
                  rules={[{ required: true, message: '请选择关联画布' }]}
                  extra="默认关联的画布为用户在画布列表点击二次触达按钮对应的画布，但也可调整关联的画布"
                >
                  <Select
                    placeholder="请选择关联画布"
                    showSearch
                    filterOption={(input, option) =>
                      (option?.label ?? '').toLowerCase().includes(input.toLowerCase())
                    }
                    options={canvasOptions}
                  />
                </Form.Item>

                <Divider />

                <div style={{ background: '#f5f5f5', padding: 16, borderRadius: 8 }}>
                  <div style={{ fontSize: 14, color: '#666', marginBottom: 8 }}>
                    <strong>已选人群信息：</strong>
                  </div>
                  <Space direction="vertical" size="small">
                    <div>
                      人群类型：
                      <span style={{ color: '#1677ff' }}>
                        {formData.audienceType === 'verified'
                          ? '领券已核销'
                          : formData.audienceType === 'unverified'
                          ? '领券未核销'
                          : '未选择'}
                      </span>
                    </div>
                    <div>
                      人群名称：
                      <span style={{ color: '#1677ff' }}>
                        {formData.audienceName || '未填写'}
                      </span>
                    </div>
                  </Space>
                </div>
              </Card>
            )}

            {/* 步骤 3：画布配置 */}
            {currentStep === 2 && (
              <Card
                title="第三步：画布配置"
                size="small"
                style={{ maxWidth: 600 }}
              >
                <Form.Item
                  label="画布描述"
                  name="description"
                  extra="描述该二次触达画布的目的和策略"
                >
                  <TextArea
                    rows={4}
                    placeholder="请描述该二次触达画布的目标、触达策略、预期效果等..."
                  />
                </Form.Item>

                <Divider />

                <div style={{ background: '#f5f5f5', padding: 16, borderRadius: 8 }}>
                  <div style={{ fontSize: 14, color: '#666', marginBottom: 8 }}>
                    <strong>配置摘要：</strong>
                  </div>
                  <Space direction="vertical" size="small">
                    <div>
                      人群类型：
                      <span style={{ color: '#1677ff' }}>
                        {formData.audienceType === 'verified'
                          ? '领券已核销'
