import {
  Table,
  Tag,
  Space,
  Button,
  Input,
  Select,
  Typography,
  Collapse,
  message,
  Modal,
} from 'antd';
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import type { ColumnsType } from 'antd/es/table';
import {
  SearchOutlined,
  PlusOutlined,
  EyeOutlined,
  EditOutlined,
  PauseCircleOutlined,
  PlayCircleOutlined,
  DeleteOutlined,
  LinkOutlined,
  UnlinkOutlined,
} from '@ant-design/icons';

const { Title } = Typography;
const { Panel } = Collapse;

export default function CanvasList() {
  const navigate = useNavigate();
  const [searchText, setSearchText] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [data, setData] = useState<Canvas[]>(mockCanvasList);
  const [expandedRowKeys, setExpandedRowKeys] = useState<React.Key[]>([]);

  // 处理二次触达按钮点击
  const handleSecondReach = (canvasId: number) => {
    navigate(`/second-reach-config/${canvasId}`);
  };

  // 处理查看画布
  const handleView = (record: Canvas) => {
    message.info(`查看画布：${record.name}`);
  };

  // 处理编辑画布
  const handleEdit = (record: Canvas) => {
    message.info(`编辑画布：${record.name}`);
  };

  // 处理启停画布
  const handleToggleStatus = (record: Canvas) => {
    const newStatus = record.status === 'active' ? 'paused' : 'active';
    const newData = data.map((item) =>
      item.id === record.id ? { ...item, status: newStatus } : item
    );
    setData(newData);
    message.success(
      `画布已${newStatus === 'active' ? '启用' : '暂停'}`
    );
  };

  // 处理删除画布
  const handleDelete = (record: Canvas) => {
    Modal.confirm({
      title: '确认删除',
      content: `确定要删除画布"${record.name}"吗？此操作不可恢复。`,
      onOk: () => {
        const newData = data.filter((item) => item.id !== record.id);
        setData(newData);
        message.success('画布已删除');
      },
    });
  };

  // 切换展开/折叠
  const toggleExpand = (canvasId: number) => {
    setExpandedRowKeys((prev) => {
      if (prev.includes(canvasId)) {
        return prev.filter((key) => key !== canvasId);
      }
      return [...prev, canvasId];
    });
  };

  const columns: ColumnsType<Canvas> = [
    {
      title: '画布名称',
      dataIndex: 'name',
      key: 'name',
      width: 200,
      render: (text: string, record: Canvas) => (
        <Space direction="vertical" size={0}>
          <span style={{ fontWeight: 500 }}>{text}</span>
          {record.secondReachCanvasName && (
            <span style={{ fontSize: 12, color: '#999' }}>
              <LinkOutlined style={{ marginRight: 4 }} />
              关联：{record.secondReachCanvasName}
            </span>
          )}
        </Space>
      ),
    },
    {
      title: '描述',
      dataIndex: 'description',
      key: 'description',
      ellipsis: true,
    },
    {
      title: '状态',
      dataIndex: 'status',
      key: 'status',
      width: 100,
      render: (status: Canvas['status']) => (
        <Tag color={statusMap[status].color}>{statusMap[status].text}</Tag>
      ),
    },
    {
      title: '人群数量',
      dataIndex: 'audienceCount',
      key: 'audienceCount',
      width: 100,
      render: (count: number) => count.toLocaleString(),
    },
    {
      title: '创建人',
      dataIndex: 'creator',
      key: 'creator',
      width: 100,
    },
    {
      title: '更新时间',
      dataIndex: 'updatedAt',
      key: 'updatedAt',
      width: 180,
    },
    {
      title: '二次触达',
      key: 'secondReach',
      width: 100,
      render: (_: unknown, record: Canvas) => (
        <Tag color={record.hasSecondReach ? 'blue' : 'default'}>
          {record.hasSecondReach ? '已配置' : '未配置'}
        </Tag>
      ),
    },
    {
      title: '操作',
      key: 'action',
      width: 280,
      render: (_: unknown, record: Canvas) => (
        <Space wrap>
          <Button
            type="link"
            size="small"
            onClick={() => handleView(record)}
            icon={<EyeOutlined />}
          >
            查看
          </Button>
          <Button
            type="link"
            size="small"
            onClick={() => handleEdit(record)}
            icon={<EditOutlined />}
          >
            编辑
          </Button>
          <Button
            type="link"
            size="small"
            onClick={() => handleSecondReach(record.id)}
            icon={<PlusOutlined />}
          >
            二次触达
          </Button>
          <Button
            type="link"
            size="small"
            onClick={() => handleToggleStatus(record)}
            icon={record.status === 'active' ? <PauseCircleOutlined /> : <PlayCircleOutlined />}
          >
            {record.status === 'active' ? '暂停' : '启用'}
          </Button>
          <Button
            type="link"
            size="small"
            danger
            onClick={() => handleDelete(record)}
            icon={<DeleteOutlined />}
          >
            删除
          </Button>
        </Space>
      ),
    },
  ];

  // 自定义行渲染，支持展开关联画布
  const expandable = {
    expandedRowKeys,
    onExpand: (expanded: boolean, record: Canvas) => {
      if (expanded && record.secondReachCanvasId) {
        const secondReachCanvas = mockCanvasList.find(
          (c) => c.id === record.secondReachCanvasId
        );
        if (secondReachCanvas) {
          setExpandedRowKeys((prev) => [...prev, record.secondReachCanvasId]);
        }
      }
    },
    expandableRowRender: (record: Canvas) => {
      if (!record.secondReachCanvasId) return null;
      const secondReachCanvas = mockCanvasList.find(
        (c) => c.id === record.secondReachCanvasId
      );
      if (!secondReachCanvas) return null;

      return (
        <div style={{ padding: '16px 24px', background: '#fafafa' }}>
          <Space direction="vertical" style={{ width: '100%' }} size="small">
            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <LinkOutlined style={{ color: '#1677ff' }} />
              <Typography.Text strong>关联的二次触达画布：</Typography.Text>
              <Tag color="blue">二次触达</Tag>
            </div>
            <Table
              columns={[
                { title: '画布名称', dataIndex: 'name', key: 'name' },
                { title: '描述', dataIndex: 'description', key: 'description', ellipsis: true },
                {
                  title: '状态',
                  dataIndex: 'status',
                  key: 'status',
                  render: (status: Canvas['status']) => (
                    <Tag color={statusMap[status].color}>{statusMap[status].text}</Tag>
                  ),
                },
                {
                  title: '人群数量',
                  dataIndex: 'audienceCount',
                  key: 'audienceCount',
                  render: (count: number) => count.toLocaleString(),
                },
                {
                  title: '操作',
                  key: 'action',
                  render: (_: unknown, r: Canvas) => (
                    <Button
                      type="link"
                      size="small"
                      onClick={() => handleView(r)}
                      icon={<EyeOutlined />}
                    >
                      查看
                    </Button>
                  ),
                },
              ]}
              dataSource={[secondReachCanvas]}
              pagination={false}
              size="small"
              style={{ marginLeft: 24 }}
            />
          </Space>
        </div>
      );
    },
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 16 }}>
        <Title level={4} style={{ margin: 0 }}>画布列表</Title>
        <Space>
          <Button type="primary" icon={<PlusOutlined />}>
            新建画布
          </Button>
        </Space>
      </div>

      <Space style={{ marginBottom: 16 }} wrap>
        <Input
          placeholder="搜索画布名称或描述"
          prefix={<SearchOutlined />}
          style={{ width: 300 }}
          value={searchText}
          onChange={(e) => setSearchText(e.target.value)}
          allowClear
        />
        <Select
          style={{ width: 150 }}
          value={statusFilter}
          onChange={setStatusFilter}
          options={[
            { value: 'all', label: '全部状态' },
            { value: 'draft', label: '草稿' },
            { value: 'active', label: '进行中' },
            { value: 'paused', label: '已暂停' },
            { value: 'ended', label: '已结束' },
          ]}
        />
      </Space>

      <Table
        columns={columns}
        dataSource={data.filter((item) => {
          const matchSearch =
            !searchText ||
            item.name.toLowerCase().includes(searchText.toLowerCase()) ||
            item.description.toLowerCase().includes(searchText.toLowerCase());
          const matchStatus =
            statusFilter === 'all' || item.status === statusFilter;
          return matchSearch && matchStatus;
        })}
        rowKey="id"
        pagination={{ pageSize: 10 }}
        expandable={expandable}
      />
    </div>
  );
}

